test_cases.assertion_pseudocode:
cfg, err := apikit.LoadConfig(); assert err == nil && cfg != nil
// malformed case:
cfg2, err2 := apikit.LoadConfig(); assert cfg2 == nil && err2 != nil

for level in ['trace','debug','info','warn','error','fatal','panic','INFO','DEBUG']:
  cfg, err := loadConfigWithLogLevel(level); assert err == nil
for level in ['verbose','WARNING','silent']:
  cfg, err := loadConfigWithLogLevel(level); assert cfg == nil && err != nil

checker_returns_nil := func() error { return nil }
resp1 := GET(server_addr + '/readyz') // with nil checker
assert resp1.status == 200 && parse_json(resp1.body) == {"status":"ready"}
assert resp1.headers['Cache-Control'] == 'no-cache'
checker_returns_err := func() error { return errors.New('db down') }
resp2 := GET(server_addr + '/readyz') // with error checker
assert resp2.status == 503 && parse_json(resp2.body) == {"status":"not ready"}
assert resp2.headers['Cache-Control'] == 'no-cache'

for path in ['/healthz', '/readyz', '/version']:
  resp := GET(server_addr + path)
  assert resp.status != 404
// confirm they are NOT mounted under mount_point:
for path in ['/api/v2/healthz', '/api/v2/readyz', '/api/v2/version']:
  resp := GET(server_addr + path)
  assert resp.status == 404

// Static analysis / code inspection:
assert constant_exists('drainTimeout') == true
assert drainTimeout == 15 * time.Second

// Code-level check: grep server initialization code for middleware.Recover()
assert not_contains_echo_builtin_recover(server_initialization_code)
// Behavioral: a panic returns exactly one HTTP 500 response, not doubled
resp := GET(server_addr + '/api/v1/panic')
assert resp.status == 500
assert count_json_error_envelopes_in_body(resp.body) == 1

for method in ['GET','DELETE','HEAD','OPTIONS']:
  resp := request(method, server_addr + '/api/v1/test', headers={'Content-Type': 'text/plain'})
  assert resp.status != 415

// Verify presence of security headers and Cache-Control from correct source:
resp := GET(server_addr + '/api/v1/test')
assert resp.headers['X-Content-Type-Options'] == 'nosniff'
assert resp.headers['Cache-Control'] == 'no-store' // from CacheMiddleware, not security headers
// Code inspection: SecurityHeadersMiddleware function body must not reference 'Cache-Control'
assert not_contains(security_headers_middleware_source, 'Cache-Control')

for s in ['not-a-timestamp', '2026/07/17', '', '2026-13-01T00:00:00Z']:
  t, err := apikit.ParseUTC(s)
  assert err != nil
  assert t == time.Time{}

// Run with: go test -race
results := run_concurrent(func() { return srv.APIGroup() }, count=10)
for g in results: assert g != nil && g == results[0]

// Compile-time check:
var cfg *apikit.Config = load_internal_config() // must not require type assertion
assert compile_succeeds(above_code)

edge_case_tests.assertion_pseudocode:
var recovered interface{}
func() {
  defer func() { recovered = recover() }()
  apikit.NewServer(nil, nil)
}()
assert recovered != nil
assert len(fmt.Sprintf('%v', recovered)) > 0
assert string_contains(fmt.Sprintf('%v', recovered), 'cfg' OR 'nil')

// Run with: go test -race
wg := sync.WaitGroup{}
errs := make([]error, 5)
for i := 0..4:
  wg.Add(1)
  go func(i int) { errs[i] = srv.Shutdown(context.Background()); wg.Done() }(i)
wg.Wait()
for err in errs: assert err == nil
